-- Seed threat actors (2026-current)
INSERT INTO threat_actors (id, name, aliases, origin, description, target_industries, first_seen, last_active, ttps) VALUES
('apt29', 'APT29', '{"Cozy Bear","The Dukes","Midnight Blizzard"}', 'Russia', 'Russian state-sponsored threat actor associated with the SVR. Continues sophisticated campaigns against Western government and technology targets, with increased focus on cloud infrastructure exploitation and AI-assisted phishing.', '{"government","defense","technology","energy"}', '2008', '2026-03-28', '{"Spear Phishing","Supply Chain Compromise","Cloud Service Exploitation","AI-Generated Lures","Token Theft","OAuth Abuse"}'),
('salt-typhoon', 'Salt Typhoon', '{"GhostEmperor","FamousSparrow","Earth Estries"}', 'China', 'Chinese state-sponsored group responsible for the 2024-2025 US telecom breaches. Has expanded operations to target 5G infrastructure and satellite communications networks globally. One of the most significant telecom threat actors ever identified.', '{"telecommunications","government","defense","technology"}', '2020', '2026-03-30', '{"Telecom Infrastructure Exploitation","Lawful Intercept Abuse","Router Implants","Living-off-the-Land","Kernel-level Rootkits"}'),
('lockbit', 'LockBit', '{"LockBit Black","LockBit 4.0","LockBit Green"}', 'Russia / Eastern Europe', 'Despite multiple law enforcement disruptions, LockBit continues to operate with rebuilt infrastructure. Version 5.0 released in early 2026 features AI-assisted target selection and automated lateral movement.', '{"healthcare","finance","manufacturing","government","education"}', '2019', '2026-03-25', '{"Ransomware-as-a-Service","Triple Extortion","AI-Assisted Targeting","Automated Lateral Movement","ESXi Encryption"}'),
('volt-typhoon', 'Volt Typhoon', '{"BRONZE SILHOUETTE","Vanguard Panda","Insidious Taurus"}', 'China', 'Chinese state-sponsored actor with confirmed pre-positioned access in US critical infrastructure including water, energy, and transportation. FBI and CISA confirmed active remediation efforts ongoing through 2026.', '{"energy","telecommunications","government","manufacturing","healthcare"}', '2021', '2026-03-15', '{"Living-off-the-Land","SOHO Router Botnets","VPN Exploitation","Firmware Persistence","OT Network Pivoting"}'),
('scattered-spider', 'Scattered Spider', '{"UNC3944","Octo Tempest","Star Fraud","0ktapus"}', 'United States / United Kingdom', 'English-speaking threat group known for social engineering attacks against major enterprises. Has evolved from SIM-swapping to sophisticated ransomware operations, increasingly partnering with Russian-speaking ransomware operators.', '{"finance","technology","telecommunications","retail","healthcare"}', '2022', '2026-03-31', '{"Social Engineering","SIM Swapping","MFA Fatigue","Help Desk Manipulation","Identity Provider Abuse","Ransomware Deployment"}'),
('cl0p', 'Cl0p', '{"TA505","FIN11","Lace Tempest"}', 'Russia / Ukraine', 'Continues mass exploitation campaigns targeting file transfer and managed file transfer appliances. Responsible for some of the largest data breaches in history through zero-day exploitation of enterprise software.', '{"finance","healthcare","government","retail","education"}', '2019', '2026-03-20', '{"Zero-Day Exploitation","Mass Data Exfiltration","File Transfer Appliance Targeting","Extortion without Encryption","Automated Exploitation"}');

-- Seed articles (March-April 2026)
INSERT INTO articles (title, slug, summary, content, threat_level, category, cves, affected_products, threat_actors, industries, attack_vector, source, source_url, published_at, updated_at, discovered_at, exploited_at, patched_at, verified, verified_by, tags, region) VALUES

('Critical Zero-Day in Palo Alto PAN-OS Firewalls Under Active Mass Exploitation', 'palo-alto-pan-os-zero-day-mass-exploitation', 'A critical unauthenticated remote code execution vulnerability in Palo Alto Networks PAN-OS is being mass exploited. Over 25,000 internet-facing devices are vulnerable. CISA has issued an emergency directive.', 'Palo Alto Networks has confirmed active exploitation of CVE-2026-0015, a critical command injection vulnerability in the GlobalProtect gateway component of PAN-OS. The vulnerability allows unauthenticated attackers to execute arbitrary commands as root on affected firewalls via specially crafted HTTPS requests. Volexity first observed exploitation on March 26, with rapid escalation to mass exploitation by March 28. Multiple threat actors, including suspected Chinese state-sponsored groups, are deploying web shells and establishing persistent access. CISA has issued Emergency Directive 26-02 requiring federal agencies to patch or mitigate within 48 hours. Palo Alto has released hotfixes for PAN-OS 11.1, 11.0, and 10.2.', 'critical', 'zero-day', '{"CVE-2026-0015"}', '{"PAN-OS 11.1","PAN-OS 11.0","PAN-OS 10.2","GlobalProtect Gateway"}', '{}', '{"government","finance","healthcare","technology","defense"}', 'Network / HTTPS GlobalProtect Gateway', 'Palo Alto Networks PSIRT / Volexity', 'https://security.paloaltonetworks.com/advisories', '2026-03-31T18:00:00Z', '2026-04-01T08:00:00Z', '2026-03-26T00:00:00Z', '2026-03-26T00:00:00Z', '2026-03-30T00:00:00Z', true, '{"CISA","Palo Alto Networks","Volexity"}', '{"zero-day","firewall","mass-exploitation","emergency-directive"}', 'Global'),

('Salt Typhoon Compromises Three Additional US Telecom Providers in Ongoing Campaign', 'salt-typhoon-three-more-us-telecoms', 'CISA and FBI confirm that Salt Typhoon has compromised three additional US telecommunications providers, bringing the total to twelve. The group maintains persistent access to lawful intercept systems.', 'A joint CISA-FBI advisory confirms that Chinese state-sponsored group Salt Typhoon has expanded its intrusion campaign to three additional major US telecommunications providers. The group, which first gained public attention in late 2024, has now compromised twelve US telecom companies. Investigators have found evidence that the group accessed lawful intercept systems, call detail records, and communications metadata for senior government officials. The campaign represents one of the most significant intelligence compromises in US history. Remediation efforts are complicated by the depth of network access and the use of sophisticated firmware-level implants on core routing infrastructure.', 'critical', 'apt', '{}', '{"Cisco IOS XR","Juniper Junos","Telecom Core Routers","Lawful Intercept Systems"}', '{"Salt Typhoon"}', '{"telecommunications","government","defense"}', 'Network Infrastructure / Router Exploitation', 'CISA / FBI Joint Advisory', 'https://www.cisa.gov/news-events/cybersecurity-advisories', '2026-03-30T14:00:00Z', '2026-03-31T10:00:00Z', '2024-09-01T00:00:00Z', '2024-09-01T00:00:00Z', NULL, true, '{"CISA","FBI","NSA"}', '{"telecom","state-sponsored","espionage","lawful-intercept","critical-infrastructure"}', 'United States'),

('LockBit 5.0 Deploys AI-Powered Ransomware with Automated Network Mapping', 'lockbit-5-ai-powered-ransomware', 'LockBit releases version 5.0 featuring an integrated AI module that automates victim network reconnaissance, identifies high-value targets, and optimizes encryption timing to maximize impact.', 'The LockBit ransomware group has released version 5.0 of their RaaS platform, representing a significant evolution in ransomware capabilities. The new version includes an AI-assisted module dubbed "LockBrain" that performs automated network reconnaissance, identifies critical systems and backup infrastructure, and determines optimal encryption timing based on victim activity patterns. The module also generates customized ransom notes based on the victim organization financial data. Initial deployments have targeted healthcare and financial services, with average ransom demands exceeding $5 million. The FBI warns that the AI capabilities significantly reduce the time from initial access to encryption, leaving defenders less time to detect and respond.', 'critical', 'ransomware', '{}', '{"Windows Server 2022/2025","VMware ESXi 8.x","Linux Enterprise","Active Directory"}', '{"LockBit"}', '{"healthcare","finance","manufacturing"}', 'RDP / VPN Exploitation / AI-Assisted Lateral Movement', 'FBI Flash Alert', 'https://www.ic3.gov/Home/IndustryAlerts', '2026-03-29T16:00:00Z', '2026-03-30T12:00:00Z', '2026-03-22T00:00:00Z', '2026-03-22T00:00:00Z', NULL, true, '{"FBI","CISA"}', '{"ransomware","ai-assisted","lockbit","healthcare","finance"}', 'Global'),

('Critical RCE Chain in Microsoft Azure Kubernetes Service Exposes Cloud Workloads', 'azure-aks-rce-chain-cloud-workloads', 'A chain of three vulnerabilities in Azure Kubernetes Service allows tenant escape and remote code execution on underlying host nodes. Microsoft has released emergency patches.', 'Microsoft has patched a critical chain of three vulnerabilities in Azure Kubernetes Service (AKS) that, when combined, allow an attacker with access to a container to escape the pod sandbox and execute arbitrary code on the underlying host node with root privileges. CVE-2026-21345 is a container escape via a Linux kernel vulnerability in the OverlayFS implementation. CVE-2026-21346 exploits a misconfiguration in the kubelet API authentication. CVE-2026-21347 allows privilege escalation to cluster-admin via a flaw in the AKS RBAC implementation. Wiz Research, which discovered the chain, estimates that approximately 40% of AKS clusters were vulnerable. Microsoft has automatically patched managed clusters and recommends immediate updates for self-managed configurations.', 'critical', 'vulnerability', '{"CVE-2026-21345","CVE-2026-21346","CVE-2026-21347"}', '{"Azure Kubernetes Service","Azure Container Instances","Linux Kernel 6.x"}', '{}', '{"technology","finance","healthcare","government"}', 'Container Escape / Privilege Escalation', 'Microsoft Security Response Center / Wiz Research', 'https://msrc.microsoft.com/update-guide', '2026-03-28T20:00:00Z', '2026-03-29T14:00:00Z', '2026-03-15T00:00:00Z', NULL, '2026-03-28T00:00:00Z', true, '{"Microsoft","Wiz Research","CISA"}', '{"cloud","kubernetes","container-escape","azure"}', 'Global'),

('Scattered Spider Breaches Major US Health Insurer, 8.2M Records Exposed', 'scattered-spider-health-insurer-breach', 'Scattered Spider has breached one of the largest US health insurance companies through social engineering of the IT help desk. Personal health information of 8.2 million members exfiltrated.', 'The Scattered Spider threat group has successfully breached a top-5 US health insurance company by social engineering the IT help desk into resetting an executive MFA token. Once inside, the group deployed legitimate remote management tools to maintain access and exfiltrated 8.2 million member records including names, SSNs, medical diagnoses, prescription histories, and insurance claim data. The breach was discovered after the group posted a sample of the data on their leak site with a $15 million ransom demand. HHS has opened an investigation under HIPAA, and the company is offering 24 months of identity and credit monitoring. This continues a pattern of Scattered Spider targeting healthcare following the 2024 Change Healthcare incident.', 'critical', 'data-breach', '{}', '{"Okta","Microsoft 365","Azure AD","ServiceNow"}', '{"Scattered Spider"}', '{"healthcare","finance"}', 'Social Engineering / Help Desk Manipulation / MFA Bypass', 'HHS / FBI Joint Advisory', 'https://www.hhs.gov/hipaa/for-professionals/breach-notification', '2026-03-27T12:00:00Z', '2026-03-28T16:00:00Z', '2026-03-20T00:00:00Z', '2026-03-15T00:00:00Z', NULL, true, '{"HHS","FBI","CISA"}', '{"data-breach","healthcare","social-engineering","hipaa","identity-theft"}', 'United States'),

('APT29 Exploits OAuth Consent Phishing in Massive Campaign Against NATO Governments', 'apt29-oauth-consent-phishing-nato', 'APT29 has launched a large-scale OAuth consent phishing campaign targeting government officials across 14 NATO member states, compromising Microsoft 365 accounts through malicious Azure app registrations.', 'Microsoft Threat Intelligence has identified an ongoing campaign by APT29 targeting government officials across 14 NATO member states using a sophisticated OAuth consent phishing technique. The group registers malicious Azure applications that request broad permissions including mail.read, files.read, and user.read. Targets receive phishing emails from compromised legitimate government accounts containing links to Microsoft login pages with the malicious app consent request. Once consent is granted, APT29 gains persistent access to the victim mailbox and OneDrive without needing the account password. Over 500 government accounts have been compromised across diplomatic, defense, and intelligence agencies. Microsoft has revoked the malicious applications and published indicators of compromise.', 'high', 'apt', '{}', '{"Microsoft 365","Azure AD","Microsoft Entra ID","Outlook"}', '{"APT29"}', '{"government","defense"}', 'OAuth Consent Phishing / Malicious App Registration', 'Microsoft Threat Intelligence', 'https://www.microsoft.com/en-us/security/blog', '2026-03-26T10:00:00Z', '2026-03-27T08:00:00Z', '2026-03-18T00:00:00Z', '2026-03-18T00:00:00Z', NULL, true, '{"Microsoft","CISA","NATO CCDCOE"}', '{"apt","oauth","phishing","state-sponsored","nato"}', 'Europe / NATO'),

('Critical Supply Chain Attack Targets Popular Python AI/ML Libraries on PyPI', 'pypi-supply-chain-ai-ml-libraries', 'A sophisticated supply chain attack has compromised three widely-used Python AI/ML packages on PyPI, injecting credential-stealing code. Combined download count exceeds 45 million.', 'Security researchers at JFrog have uncovered a sophisticated supply chain attack targeting three popular Python AI/ML libraries on PyPI. The attacker compromised maintainer accounts through credential stuffing and published malicious versions that exfiltrate cloud provider credentials, API keys, and ML model weights to attacker infrastructure. The compromised packages had a combined weekly download count exceeding 45 million, and the malicious versions were live for approximately 72 hours before detection. The malware specifically targets AWS, GCP, and Azure credentials, as well as OpenAI, Anthropic, and Hugging Face API keys. Organizations using these packages are advised to rotate all cloud and AI service credentials immediately. PyPI has removed the affected versions and implemented additional maintainer verification requirements.', 'high', 'supply-chain', '{"CVE-2026-31001","CVE-2026-31002","CVE-2026-31003"}', '{"PyPI ecosystem","Python AI/ML applications","AWS","GCP","Azure"}', '{}', '{"technology","finance","healthcare"}', 'Supply Chain / Package Repository Compromise', 'JFrog Security Research', 'https://jfrog.com/blog/security-research', '2026-03-25T22:00:00Z', '2026-03-26T14:00:00Z', '2026-03-25T16:00:00Z', NULL, NULL, true, '{"JFrog","PyPI Security","CISA"}', '{"supply-chain","pypi","ai-ml","credential-theft","python"}', 'Global'),

('Volt Typhoon Pre-Positioned in US Water Systems Triggers Emergency Response', 'volt-typhoon-water-systems-emergency', 'EPA issues emergency order after confirming Volt Typhoon has pre-positioned access in water treatment systems serving over 20 million Americans. SCADA manipulation capabilities confirmed.', 'The EPA has issued an emergency enforcement order after CISA confirmed that Chinese state-sponsored group Volt Typhoon maintains persistent access to water treatment SCADA systems serving over 20 million Americans across six states. The group has demonstrated the capability to manipulate water treatment chemical dosing systems, though no actual manipulation has been attempted. Access was achieved through exploitation of internet-exposed OT devices and lateral movement from compromised IT networks. The advisory notes that the group has been present in some systems since at least 2023. Emergency response includes deployment of EPA and CISA rapid response teams to affected facilities, mandatory network segmentation of OT systems, and implementation of manual override capabilities for critical treatment processes.', 'critical', 'apt', '{}', '{"SCADA Systems","Programmable Logic Controllers","Historian Servers","HMI Systems","OT Networks"}', '{"Volt Typhoon"}', '{"energy","government","healthcare"}', 'OT Device Exploitation / IT-OT Lateral Movement', 'EPA / CISA Emergency Advisory', 'https://www.epa.gov/cybersecurity', '2026-03-24T15:00:00Z', '2026-03-25T11:00:00Z', '2023-06-01T00:00:00Z', '2023-06-01T00:00:00Z', NULL, true, '{"EPA","CISA","FBI","NSA"}', '{"critical-infrastructure","water","scada","ot-security","state-sponsored"}', 'United States'),

('Google Chrome Zero-Day Exploited by Commercial Spyware Vendor Targeting Journalists', 'chrome-zero-day-spyware-journalists', 'Google patches a V8 zero-day actively exploited by a commercial spyware vendor to target journalists and human rights activists. Full chain achieves remote code execution with a single click.', 'Google Threat Analysis Group has disclosed CVE-2026-1893, a type confusion vulnerability in Chrome V8 JavaScript engine being actively exploited by a European commercial spyware vendor. The exploit chain achieves full sandbox escape and remote code execution through a single malicious link — no additional interaction required. TAG identified the campaign targeting journalists, human rights activists, and opposition politicians in three countries. The spyware payload includes full device monitoring, encrypted messaging interception, and microphone/camera activation. Google has released Chrome 134.0.6998.89 to address the vulnerability and has filed legal action against the spyware vendor. All Chromium-based browsers including Edge, Brave, and Opera are affected.', 'high', 'zero-day', '{"CVE-2026-1893"}', '{"Google Chrome 134","Microsoft Edge","Chromium-based Browsers","Android WebView"}', '{}', '{"technology","government"}', 'Web / Malicious Link / One-Click Exploit', 'Google Threat Analysis Group', 'https://blog.google/threat-analysis-group', '2026-03-23T20:00:00Z', '2026-03-24T10:00:00Z', '2026-03-19T00:00:00Z', '2026-03-19T00:00:00Z', '2026-03-23T00:00:00Z', true, '{"Google TAG"}', '{"zero-day","spyware","browser","journalists","surveillance"}', 'Global'),

('Cl0p Exploits New Cleo File Transfer Zero-Day in Mass Data Theft Campaign', 'cl0p-cleo-file-transfer-zero-day', 'Cl0p ransomware group is mass exploiting a zero-day in Cleo file transfer products, marking their fourth major file transfer appliance campaign. Over 600 organizations confirmed compromised.', 'The Cl0p ransomware group has launched another mass exploitation campaign, this time targeting a zero-day vulnerability (CVE-2026-27891) in Cleo Harmony, Cleo VLTrader, and Cleo LexiCom file transfer products. The vulnerability allows unauthenticated remote code execution via a deserialization flaw in the file processing engine. Cl0p has been systematically exfiltrating data from compromised organizations before posting them on their leak site. Huntress first detected exploitation on March 18, and estimates that over 600 organizations have been compromised. This marks Cl0p fourth major file transfer appliance campaign following Accellion (2021), GoAnywhere (2023), and MOVEit (2023). Cleo has released emergency patches and recommends immediate application along with network isolation of file transfer systems.', 'high', 'supply-chain', '{"CVE-2026-27891"}', '{"Cleo Harmony","Cleo VLTrader","Cleo LexiCom"}', '{"Cl0p"}', '{"finance","retail","manufacturing","healthcare","government"}', 'Web / File Transfer Appliance Exploitation', 'Huntress / Cleo Security Advisory', 'https://www.cleo.com/cleo-security-advisory', '2026-03-22T11:00:00Z', '2026-03-23T09:00:00Z', '2026-03-18T00:00:00Z', '2026-03-18T00:00:00Z', '2026-03-21T00:00:00Z', true, '{"Huntress","CISA","Cleo"}', '{"file-transfer","zero-day","mass-exploitation","data-theft","cl0p"}', 'Global'),

('NIST NVD Backlog Crisis: 30,000+ CVEs Unanalyzed as Funding Dispute Continues', 'nist-nvd-backlog-crisis-30k-cves', 'The NIST National Vulnerability Database backlog has exceeded 30,000 unanalyzed CVEs, creating blind spots in vulnerability management programs worldwide. Industry coalition demands congressional action.', 'The NIST National Vulnerability Database (NVD) backlog has grown to over 30,000 unanalyzed CVEs as of March 2026, more than double the backlog from a year ago. The growing backlog means that thousands of vulnerabilities lack CVSS scores, CPE data, and other enrichment data that vulnerability management tools depend on for prioritization. An industry coalition including the Cybersecurity Coalition, BSA, and ITI has sent a letter to Congress demanding emergency funding for NVD operations. CISA has expanded its Vulnrichment program to help fill the gap, but coverage remains incomplete. Security teams are increasingly relying on alternative enrichment sources including VulnCheck, OSV, and vendor-specific advisories. The backlog has been particularly impactful for healthcare and government organizations that rely on NVD data for compliance requirements.', 'medium', 'vulnerability', '{}', '{"NIST NVD","Vulnerability Management Tools","CVSS Scoring","CPE Dictionary"}', '{}', '{"technology","healthcare","government","finance"}', 'N/A — Systemic Risk', 'Cybersecurity Coalition / CISA', 'https://www.nist.gov/nvd', '2026-03-20T09:00:00Z', '2026-03-21T15:00:00Z', '2025-02-01T00:00:00Z', NULL, NULL, true, '{"NIST","CISA"}', '{"nvd","vulnerability-management","cvss","systemic-risk","compliance"}', 'United States'),

('Critical Fortinet FortiManager Flaw Allows Remote Takeover of Managed Firewalls', 'fortinet-fortimanager-remote-takeover', 'A critical vulnerability in FortiManager allows attackers to register rogue FortiGate devices and execute arbitrary code, potentially compromising entire managed firewall estates.', 'Fortinet has disclosed CVE-2026-48788, a critical vulnerability in FortiManager that allows unauthenticated attackers to register rogue FortiGate devices to a FortiManager instance. Once registered, the attacker can push malicious configuration to all managed firewalls, effectively compromising the entire managed estate. The vulnerability has a CVSS score of 9.8 and has been observed in targeted attacks attributed to UNC3886. Mandiant reports that threat actors are using the vulnerability to deploy custom firmware implants on managed FortiGate devices, providing persistent access that survives factory resets. Organizations using FortiManager are urged to patch immediately and audit their registered device inventory for unauthorized entries.', 'critical', 'vulnerability', '{"CVE-2026-48788"}', '{"FortiManager 7.4","FortiManager 7.6","FortiGate Managed Firewalls"}', '{"Salt Typhoon"}', '{"government","finance","energy","telecommunications","defense"}', 'Network / FortiManager Registration Protocol', 'Fortinet PSIRT / Mandiant', 'https://www.fortiguard.com/psirt', '2026-03-18T16:00:00Z', '2026-03-19T12:00:00Z', '2026-03-10T00:00:00Z', '2026-03-12T00:00:00Z', '2026-03-18T00:00:00Z', true, '{"CISA","Fortinet PSIRT","Mandiant"}', '{"firewall","fortimanager","network-edge","firmware-implant"}', 'Global');
